import { createOpenRouter } from "@openrouter/ai-sdk-provider";
import { generateObject } from "ai";
import { NextResponse } from "next/server";
import { z } from "zod";

const SUPPORTED_TASKS = [
  "validate-user-definition",
  "validate-user-sentence",
] as const;

const feedbackSchema = z.object({
  correct: z.boolean(),
  exampleSentence: z.string(),
  aiResponse: z.string(),
  hint: z.string(),
});

const chatRequestSchema = z.object({
  task: z.string().optional(),
  message: z.string().optional(),
  data: z.record(z.string(), z.unknown()).optional(),
});

type SupportedTask = (typeof SUPPORTED_TASKS)[number];

const getString = (data: Record<string, unknown>, key: string) => {
  const value = data[key];
  return typeof value === "string" ? value.trim() : "";
};

const badRequest = (message: string) =>
  NextResponse.json({ success: false, message }, { status: 400 });

const validateTask = (task: string | undefined): task is SupportedTask => {
  return SUPPORTED_TASKS.includes(task as SupportedTask);
};

export async function POST(request: Request) {
  let body: z.infer<typeof chatRequestSchema>;

  try {
    body = chatRequestSchema.parse(await request.json());
  } catch {
    return badRequest("Invalid JSON request body.");
  }

  if (!body.task) {
    return badRequest(
      `Missing task. Supported tasks: ${SUPPORTED_TASKS.join(", ")}.`
    );
  }

  if (!validateTask(body.task)) {
    return badRequest(
      `Unsupported task "${body.task}". Supported tasks: ${SUPPORTED_TASKS.join(
        ", "
      )}.`
    );
  }

  const data = body.data ?? {};
  const word = getString(data, "word");
  const exampleSentence = getString(data, "exampleSentence");
  const apiKey = process.env.OPENROUTER_KEY;

  if (!word) {
    return badRequest("Missing required field: data.word.");
  }

  if (!apiKey) {
    return NextResponse.json(
      {
        success: false,
        message: "AI feedback is not configured on the server.",
      },
      { status: 500 }
    );
  }

  const openrouter = createOpenRouter({
    apiKey,
    compatibility: "strict",
  });

  try {
    const result =
      body.task === "validate-user-definition"
        ? await validateDefinition({
            data,
            exampleSentence,
            model: openrouter.chat(
              process.env.OPENROUTER_MODEL ?? "openai/gpt-4o-mini"
            ),
            word,
          })
        : await validateSentence({
            data,
            exampleSentence,
            message: body.message ?? "",
            model: openrouter.chat(
              process.env.OPENROUTER_MODEL ?? "openai/gpt-4o-mini"
            ),
            word,
          });

    return NextResponse.json({ success: true, result: result.object });
  } catch (error) {
    console.error("Vocabulary feedback error:", error);

    return NextResponse.json(
      {
        success: false,
        message: "Unable to generate vocabulary feedback.",
      },
      { status: 500 }
    );
  }
}

async function validateDefinition({
  data,
  exampleSentence,
  model,
  word,
}: {
  data: Record<string, unknown>;
  exampleSentence: string;
  model: Parameters<typeof generateObject>[0]["model"];
  word: string;
}) {
  const userDefinition = getString(data, "userDefinition");
  const correctDefinition = getString(data, "correctDefinition");

  if (!userDefinition) {
    throw new Error("Missing required field: data.userDefinition.");
  }

  if (!correctDefinition) {
    throw new Error("Missing required field: data.correctDefinition.");
  }

  return generateObject({
    model,
    schema: feedbackSchema,
    mode: "json",
    temperature: 0.2,
    system:
      "You are a concise SAT vocabulary tutor. Return only structured JSON that matches the schema.",
    prompt: `Evaluate whether the learner's definition captures the meaning of the vocabulary word.

Word: ${word}
Correct definition: ${correctDefinition}
Example sentence: ${exampleSentence || "No example provided."}
Learner definition: ${userDefinition}

Mark correct only when the learner's definition is substantially accurate. Give brief, encouraging feedback and a short hint if it is incorrect.`,
  });
}

async function validateSentence({
  data,
  exampleSentence,
  message,
  model,
  word,
}: {
  data: Record<string, unknown>;
  exampleSentence: string;
  message: string;
  model: Parameters<typeof generateObject>[0]["model"];
  word: string;
}) {
  const userSentence = getString(data, "userSentence") || message.trim();
  const definition =
    getString(data, "definition") || getString(data, "correctDefinition");
  const partOfSpeech = getString(data, "partOfSpeech");

  if (!userSentence) {
    throw new Error("Missing required field: data.userSentence.");
  }

  if (!definition) {
    throw new Error("Missing required field: data.definition.");
  }

  return generateObject({
    model,
    schema: feedbackSchema,
    mode: "json",
    temperature: 0.2,
    system:
      "You are a concise SAT vocabulary writing tutor. Return only structured JSON that matches the schema.",
    prompt: `Evaluate whether the learner wrote an original, grammatical sentence that uses the vocabulary word correctly in context.

Word: ${word}
Part of speech: ${partOfSpeech || "Unknown"}
Definition: ${definition}
Reference example: ${exampleSentence || "No example provided."}
Learner sentence: ${userSentence}

Mark correct only if the sentence includes the target word and uses it with the intended meaning. Give tutor-style feedback in one or two sentences. If incorrect, include a specific hint. Provide one polished example sentence using the word correctly.`,
