"use client";

import * as React from "react";
import { Check, ChevronDown } from "lucide-react";
import { cn } from "@/lib/utils";

export interface Workspace {
  id: string;
  name: string;
  logo?: string;
  plan?: string;
}

type WorkspacesContextValue<T extends Workspace> = {
  workspaces: T[];
  selectedWorkspace?: T;
  onWorkspaceChange: (workspace: T) => void;
  open: boolean;
  setOpen: React.Dispatch<React.SetStateAction<boolean>>;
};

const WorkspacesContext =
  React.createContext<WorkspacesContextValue<Workspace> | null>(null);

function useWorkspacesContext() {
  const context = React.useContext(WorkspacesContext);

  if (!context) {
    throw new Error("Workspace components must be used inside Workspaces.");
  }

  return context;
}

export function Workspaces<T extends Workspace>({
  children,
  workspaces,
  selectedWorkspaceId,
  onWorkspaceChange,
}: {
  children: React.ReactNode;
  workspaces: T[];
  selectedWorkspaceId?: string;
  onWorkspaceChange: (workspace: T) => void;
}) {
  const [open, setOpen] = React.useState(false);
  const selectedWorkspace =
    workspaces.find((workspace) => workspace.id === selectedWorkspaceId) ||
    workspaces[0];

  const value = React.useMemo(
    () => ({
      workspaces,
      selectedWorkspace,
      onWorkspaceChange: onWorkspaceChange as (workspace: Workspace) => void,
      open,
      setOpen,
    }),
    [workspaces, selectedWorkspace, onWorkspaceChange, open]
  );

  return (
    <WorkspacesContext.Provider value={value}>
      <div className="relative">{children}</div>
    </WorkspacesContext.Provider>
  );
}

export function WorkspaceTrigger({ className }: { className?: string }) {
  const { selectedWorkspace, open, setOpen } = useWorkspacesContext();

  return (
    <button
      type="button"
      className={cn(
        "flex h-10 w-full items-center justify-between rounded-md border bg-background px-3 py-2 text-sm shadow-xs transition-colors hover:bg-accent",
        className
      )}
      onClick={() => setOpen((current) => !current)}
    >
      <span className="truncate font-medium">
        {selectedWorkspace?.name || "Select workspace"}
      </span>
      <ChevronDown
        className={cn("size-4 opacity-70 transition-transform", {
          "rotate-180": open,
        })}
      />
    </button>
  );
}

export function WorkspaceContent({ title }: { title?: string }) {
  const {
    workspaces,
    selectedWorkspace,
    onWorkspaceChange,
    open,
    setOpen,
  } = useWorkspacesContext();

  if (!open) return null;

  return (
    <div className="absolute right-0 z-50 mt-2 w-full min-w-72 rounded-md border bg-background p-2 shadow-lg">
      {title && (
        <div className="px-2 pb-2 text-xs font-medium text-muted-foreground">
          {title}
        </div>
      )}
      <div className="space-y-1">
        {workspaces.map((workspace) => (
          <button
            key={workspace.id}
            type="button"
            className="flex w-full items-center justify-between rounded-sm px-2 py-2 text-left text-sm hover:bg-accent"
            onClick={() => {
              onWorkspaceChange(workspace);
              setOpen(false);
            }}
          >
            <span className="truncate">{workspace.name}</span>
            {selectedWorkspace?.id === workspace.id && (
              <Check className="size-4 text-blue-600" />
            )}
          </button>
        ))}
      </div>
    </div>
  );
}

