"use client";

import * as React from "react";
import { type AssessmentWorkspace } from "@/app/dashboard/types";

export const assessmentWorkspaces: AssessmentWorkspace[] = [
  {
    id: "sat",
    name: "SAT",
    logo: "SAT",
    plan: "Question Bank",
    assessmentId: 99,
  },
  {
    id: "psat-nmsqt",
    name: "PSAT/NMSQT & PSAT 10",
    logo: "PSAT",
    plan: "Question Bank",
    assessmentId: 100,
  },
  {
    id: "psat-89",
    name: "PSAT 8/9",
    logo: "PSAT",
    plan: "Question Bank",
    assessmentId: 102,
  },
];

type AssessmentState = {
  selectedAssessment: AssessmentWorkspace;
  activeAssessmentId: string;
};

type AssessmentContextValue = {
  state: AssessmentState;
  setActiveAssessmentByWorkspace: (workspace: AssessmentWorkspace) => void;
  getAssessmentKey: (assessment?: AssessmentWorkspace) => string;
};

const defaultAssessment = assessmentWorkspaces[0];

const AssessmentContext = React.createContext<AssessmentContextValue | null>(
  null
);

export function AssessmentProvider({ children }: { children: React.ReactNode }) {
  const [state, setState] = React.useState<AssessmentState>({
    selectedAssessment: defaultAssessment,
    activeAssessmentId: defaultAssessment.id,
  });

  const setActiveAssessmentByWorkspace = React.useCallback(
    (workspace: AssessmentWorkspace) => {
      setState({
        selectedAssessment: workspace,
        activeAssessmentId: workspace.id,
      });
    },
    []
  );

  const getAssessmentKey = React.useCallback(
    (assessment?: AssessmentWorkspace) => {
      if (!assessment) return "SAT";

      const assessmentMap: Record<string, string> = {
        SAT: "SAT",
        "PSAT/NMSQT & PSAT 10": "PSAT/NMSQT",
        "PSAT 8/9": "PSAT",
      };

      return assessmentMap[assessment.name] || "SAT";
    },
    []
  );

  const value = React.useMemo(
    () => ({
      state,
      setActiveAssessmentByWorkspace,
      getAssessmentKey,
    }),
    [state, setActiveAssessmentByWorkspace, getAssessmentKey]
  );

  return (
    <AssessmentContext.Provider value={value}>
      {children}
    </AssessmentContext.Provider>
  );
}

export function useAssessment() {
  const context = React.useContext(AssessmentContext);

  if (!context) {
    throw new Error("useAssessment must be used inside AssessmentProvider.");
  }

  return context;
}

export type { AssessmentWorkspace };

