import { UserProfileWithHistory } from "@/types/userProfile";

const USER_PROFILE_KEY = "userProfile";

const defaultUserProfile: UserProfileWithHistory = {
  level: 1,
  totalXP: 0,
  questionsAnswered: 0,
  correctAnswers: 0,
};

export function getUserProfile(): UserProfileWithHistory {
  if (typeof window === "undefined") return defaultUserProfile;

  try {
    const storedProfile = localStorage.getItem(USER_PROFILE_KEY);
    return storedProfile
      ? { ...defaultUserProfile, ...JSON.parse(storedProfile) }
      : defaultUserProfile;
  } catch (error) {
    console.error("Error loading user profile:", error);
    return defaultUserProfile;
  }
}

export function saveUserProfile(profile: UserProfileWithHistory) {
  if (typeof window === "undefined") return;

  localStorage.setItem(
    USER_PROFILE_KEY,
    JSON.stringify({ ...profile, updatedAt: new Date().toISOString() })
  );
}

