"use client";

import * as React from "react";
import { Badge } from "@/components/ui/badge";

export default function CardFlip({
  word,
  partOfSpeech,
  difficulty,
  definition,
  example,
  categories = [],
  isFlipped,
  onFlip,
}: {
  isVocabCard?: boolean;
  word: string;
  partOfSpeech: string;
  difficulty: string;
  definition: string;
  example: string;
  categories?: string[];
  isFlipped?: boolean;
  onFlip?: (flipped: boolean) => void;
}) {
  const [internalFlipped, setInternalFlipped] = React.useState(false);
  const flipped = isFlipped ?? internalFlipped;

  const handleFlip = () => {
    const nextValue = !flipped;
    setInternalFlipped(nextValue);
    onFlip?.(nextValue);
  };

  return (
    <button
      type="button"
      className="min-h-80 w-full max-w-xl rounded-2xl border bg-white p-8 text-left shadow-sm transition hover:shadow-md"
      onClick={handleFlip}
    >
      {!flipped ? (
        <div className="flex min-h-64 flex-col items-center justify-center gap-4 text-center">
          <h2 className="text-4xl font-bold text-gray-900">{word}</h2>
          <div className="flex flex-wrap items-center justify-center gap-2">
            <Badge variant="outline">{partOfSpeech}</Badge>
            <Badge variant="outline">{difficulty}</Badge>
          </div>
          <p className="text-sm text-muted-foreground">
            Click to reveal definition
          </p>
        </div>
      ) : (
        <div className="space-y-5">
          <div>
            <h2 className="text-3xl font-bold text-gray-900">{word}</h2>
            <p className="text-sm text-muted-foreground">{partOfSpeech}</p>
          </div>
          <div>
            <h3 className="font-semibold text-gray-900">Definition</h3>
            <p className="text-gray-700">{definition}</p>
          </div>
          <div>
            <h3 className="font-semibold text-gray-900">Example</h3>
            <p className="italic text-gray-700">"{example}"</p>
          </div>
          {categories.length > 0 && (
            <div className="flex flex-wrap gap-2">
              {categories.map((category) => (
                <Badge key={category} variant="secondary">
                  {category}
                </Badge>
              ))}
            </div>
          )}
        </div>
      )}
    </button>
  );
}

"use client";

export function TrackerTab() {
  return (
    <div className="rounded-lg border p-6">
      <h2 className="text-xl font-semibold">Tracker</h2>
      <p className="text-sm text-muted-foreground">
        Progress tracking appears as practice data is saved.
      </p>
    </div>
  );
}

