"use client";

import Link from "next/link";
import { Button } from "@/components/ui/button";

export default function ContinuePracticeRushButton() {
  return (
    <div className="mb-6">
      <Link href="/practice">
        <Button variant="outline" className="rounded-full">
          Continue Practice
        </Button>
      </Link>
    </div>
  );
}

"use client";

import * as React from "react";
import { cn } from "@/lib/utils";

export function DuolingoToggle({
  isEnabled,
  onToggle,
  title,
  description,
  enabledDescription,
  disabledDescription,
  enabledIcon,
  disabledIcon,
  color = "blue",
}: {
  isEnabled: boolean;
  onToggle: (enabled: boolean) => void;
  title: string;
  description?: string;
  enabledDescription?: string;
  disabledDescription?: string;
  enabledIcon?: React.ReactNode;
  disabledIcon?: React.ReactNode;
  color?: "blue" | "green" | string;
}) {
  const activeColor =
    color === "green" ? "bg-green-500 border-green-600" : "bg-blue-500 border-blue-600";

  return (
    <button
      type="button"
      className={cn(
        "w-full rounded-2xl border-2 border-b-4 p-4 text-left transition-all",
        isEnabled ? "border-blue-300 bg-blue-50" : "border-gray-200 bg-white"
      )}
      onClick={() => onToggle(!isEnabled)}
    >
      <div className="flex items-center gap-4">
        <div
          className={cn(
            "flex size-10 items-center justify-center rounded-full border-b-2 text-white",
            isEnabled ? activeColor : "border-gray-300 bg-gray-300"
          )}
        >
          {isEnabled ? enabledIcon : disabledIcon}
        </div>
        <div className="flex-1">
          <div className="font-semibold text-gray-900">{title}</div>
          {description && (
            <div className="text-sm text-muted-foreground">{description}</div>
          )}
          <div className="mt-1 text-sm text-gray-700">
            {isEnabled ? enabledDescription : disabledDescription}
          </div>
        </div>
        <div
          className={cn(
            "h-7 w-12 rounded-full p-1 transition-colors",
            isEnabled ? "bg-blue-500" : "bg-gray-300"
          )}
        >
          <div
            className={cn(
              "size-5 rounded-full bg-white transition-transform",
              isEnabled && "translate-x-5"
            )}
          />
        </div>
      </div>
    </button>
  );
}

