"use client";

import * as React from "react";
import confetti from "canvas-confetti";

export type ConfettiRef = {
  fire: (options?: confetti.Options) => void;
};

export const Confetti = React.forwardRef<
  ConfettiRef,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  React.useImperativeHandle(ref, () => ({
    fire: (options) => {
      confetti({
        particleCount: 80,
        spread: 70,
        origin: { y: 0.6 },
        ...options,
      });
    },
  }));

  return <div className={className} {...props} />;
});

Confetti.displayName = "Confetti";

"use client";

import { Button } from "@/components/ui/button";
import { PracticeSession } from "@/types/session";

export default function PracticeRushCelebration({
  sessionData,
  onContinue,
}: {
  sessionData: PracticeSession;
  onContinue: () => void;
  correctAnswerChoices?: Record<string, string[]>;
}) {
  return (
    <div className="flex min-h-[80vh] items-center justify-center p-8">
      <div className="max-w-md space-y-4 text-center">
        <div className="text-6xl">🎉</div>
        <h2 className="text-3xl font-bold">Practice Complete</h2>
        <p className="text-muted-foreground">
          You answered {sessionData.answeredQuestions.length} questions.
        </p>
        <Button onClick={onContinue}>Continue Practicing</Button>
      </div>
    </div>
  );
}

"use client";

export default function OnboardCard({
  steps,
  currentStep,
}: {
  steps: { id: string; title: string; content: string }[];
  currentStep: number;
  onStepChange?: (step: number) => void;
}) {
  const activeStep = steps[currentStep] || steps[0];

  return (
    <div className="w-full max-w-md rounded-2xl border bg-white p-6 text-center shadow-sm">
      <div className="mb-4 text-sm text-muted-foreground">
        Step {Math.min(currentStep + 1, steps.length)} of {steps.length}
      </div>
      <h2 className="text-2xl font-bold text-gray-900">
        {activeStep?.title || "Loading"}
      </h2>
      <p className="mt-2 text-gray-600">{activeStep?.content}</p>
      <div className="mt-6 h-2 rounded-full bg-gray-200">
        <div
          className="h-2 rounded-full bg-blue-500 transition-all"
          style={{
            width: `${steps.length ? ((currentStep + 1) / steps.length) * 100 : 0}%`,
          }}
        />
      </div>
    </div>
  );
}

"use client";

export function GradientBars({ colors }: { colors?: string[] }) {
  const [first = "#bfdbfe", second = "transparent"] = colors || [];

  return (
    <div
      aria-hidden="true"
      className="pointer-events-none absolute inset-0 opacity-40"
      style={{
        background: `repeating-linear-gradient(135deg, ${first} 0 12px, ${second} 12px 24px)`,
      }}
    />
  );
}

"use client";

import * as React from "react";
import { X } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export function ProjectBanner({
  className,
  icon,
  label,
  callToAction,
  onClose,
  variant = "default",
}: {
  className?: string;
  icon?: React.ReactNode;
  label: React.ReactNode;
  callToAction?: { label: string; onClick: () => void };
  onClose?: () => void;
  variant?: "default" | "error" | "warning" | "success";
}) {
  return (
    <div
      className={cn(
        "fixed bottom-4 left-1/2 z-50 flex w-[min(92vw,720px)] -translate-x-1/2 items-center gap-3 rounded-xl border bg-white p-4 shadow-lg",
        variant === "error" && "border-red-200 bg-red-50",
        className
      )}
    >
      {icon}
      <div className="flex-1 text-sm">{label}</div>
      {callToAction && (
        <Button variant="outline" size="sm" onClick={callToAction.onClick}>
          {callToAction.label}
        </Button>
      )}
      {onClose && (
        <button type="button" className="rounded p-1" onClick={onClose}>
          <X className="size-4" />
        </button>
      )}
    </div>
  );
}

