"use client";

import * as React from "react";
import { cn } from "@/lib/utils";

export function WarpBackground({
  children,
  className,
}: React.HTMLAttributes<HTMLDivElement> & {
  disableAnimation?: boolean;
}) {
  return (
    <div className={cn("relative overflow-hidden bg-background", className)}>
      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_top,_rgba(59,130,246,0.12),transparent_45%)]" />
      <div className="relative z-10">{children}</div>
    </div>
  );
}

"use client";

import * as React from "react";

export function MultiIconDisplay({
  icons,
}: {
  icons: React.ReactNode[];
  theme?: "light" | "dark";
}) {
  return (
    <div className="flex items-center justify-center gap-3">
      {icons.map((icon, index) => (
        <div
          key={index}
          className="flex size-12 items-center justify-center rounded-full border bg-white text-blue-500 shadow-sm"
        >
          {icon}
        </div>
      ))}
    </div>
  );
}

"use client";

import * as React from "react";
import { Check, ChevronDown } from "lucide-react";
import { cn } from "@/lib/utils";

type Option = {
  value: string;
  label: string;
  id?: string;
  group?: string;
  groupLabel?: string;
  description?: string;
};

export function MultiSelectCombobox({
  label,
  options,
  value,
  onChange,
  renderItem,
  renderSelectedItem,
  className,
  ...props
}: {
  label: React.ReactNode;
  options: Option[];
  value: string[];
  onChange: (value: string[]) => void;
  renderItem?: (option: Option) => React.ReactNode;
  renderSelectedItem?: (value: string[]) => React.ReactNode;
  grouped?: boolean;
  className?: string;
} & Omit<React.HTMLAttributes<HTMLDivElement>, "onChange">) {
  const [open, setOpen] = React.useState(false);
  const selectedLabel = renderSelectedItem?.(value);

  const toggleValue = (nextValue: string) => {
    onChange(
      value.includes(nextValue)
        ? value.filter((currentValue) => currentValue !== nextValue)
        : [...value, nextValue]
    );
  };

  return (
    <div className={cn("relative min-w-56", className)} {...props}>
      <button
        type="button"
        className="flex h-10 w-full items-center justify-between gap-2 rounded-md border bg-background px-3 text-sm shadow-xs hover:bg-accent"
        onClick={() => setOpen((current) => !current)}
      >
        <span className="truncate">
          {selectedLabel || (value.length ? `${value.length} selected` : label)}
        </span>
        <ChevronDown className="size-4 opacity-70" />
      </button>

      {open && (
        <div className="absolute z-50 mt-2 max-h-80 w-full overflow-auto rounded-md border bg-background p-2 shadow-lg">
          {options.length === 0 ? (
            <div className="px-2 py-3 text-sm text-muted-foreground">
              No options
            </div>
          ) : (
            options.map((option) => {
              const selected = value.includes(option.value);

              return (
                <button
                  key={option.value}
                  type="button"
                  className="flex w-full items-center justify-between gap-2 rounded-sm px-2 py-2 text-left text-sm hover:bg-accent"
                  onClick={() => toggleValue(option.value)}
                >
                  <span className="min-w-0 flex-1">
                    {renderItem ? renderItem(option) : option.label}
                  </span>
