"use client";

import { Button } from "@/components/ui/button";

export type Step = {
  id: string;
  title: string;
  description: string;
  targetSelector?: string;
  completed?: boolean;
  biggerZIndex?: boolean;
  requirePreviousStep?: boolean;
};

export function InteractiveOnboardingChecklist({
  steps,
  open,
  onOpenChange,
  onCompleteStep,
}: {
  steps: Step[];
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onCompleteStep?: (stepId: string) => void;
  onFinish?: () => void;
  mode?: string;
  placement?: string;
  tourLocalStorageKey?: string;
}) {
  if (!open) return null;

  return (
    <div className="fixed right-4 top-24 z-50 w-80 rounded-xl border bg-white p-4 shadow-lg">
      <div className="mb-3 flex items-center justify-between gap-3">
        <h3 className="font-semibold">Question Bank Tour</h3>
        <Button variant="outline" size="sm" onClick={() => onOpenChange(false)}>
          Close
        </Button>
      </div>
      <div className="space-y-2">
        {steps.map((step) => (
          <button
            key={step.id}
            type="button"
            className="w-full rounded-md border p-2 text-left text-sm hover:bg-accent"
            onClick={() => onCompleteStep?.(step.id)}
          >
            <div className="font-medium">{step.title}</div>
            <div className="text-xs text-muted-foreground">
              {step.description}
            </div>
          </button>
        ))}
      </div>
    </div>
  );
}

"use client";

export function Error({
  children,
  size = "small",
}: {
  children: React.ReactNode;
  size?: "small" | "large";
}) {
  return (
    <p className={size === "large" ? "text-sm text-red-600" : "text-xs text-red-600"}>
      {children}
    </p>
  );
}

"use client";

import { Button } from "@/components/ui/button";

export function TourAlertDialog({
  isOpen,
  setIsOpen,
  startTour,
  tourTitle,
  tourDescription,
}: {
  isOpen: boolean;
  setIsOpen: (open: boolean) => void;
  startTour: () => void;
  tourLocalStorageKey?: string;
  tourTitle: string;
  tourDescription: string;
}) {
  if (!isOpen) return null;

  return (
    <div className="fixed bottom-4 right-4 z-50 max-w-sm rounded-xl border bg-white p-4 shadow-lg">
      <h3 className="font-semibold">{tourTitle}</h3>
      <p className="mt-1 text-sm text-muted-foreground">{tourDescription}</p>
      <div className="mt-4 flex justify-end gap-2">
        <Button variant="outline" size="sm" onClick={() => setIsOpen(false)}>
          Skip
        </Button>
        <Button size="sm" onClick={startTour}>
          Start
        </Button>
      </div>
    </div>
  );
}

"use client";

export type RangeValue = {
  start: Date;
  end: Date | null;
};

export function Calendar({
  value,
  onChange,
  onClick,
  allowClear,
}: {
  compact?: boolean;
  allowClear?: boolean;
  dataOnboard?: string;
  disableFuture?: boolean;
  isDocsPage?: boolean;
  showTimeInput?: boolean;
  value?: RangeValue | null;
  onChange?: (value: RangeValue | null) => void;
  onClick?: () => void;
}) {
  const toInputValue = (date?: Date | null) =>
    date ? date.toISOString().slice(0, 10) : "";

  return (
    <div className="flex items-center gap-2" onClick={onClick}>
      <input
        type="date"
        className="h-10 rounded-md border bg-background px-3 text-sm"
        value={toInputValue(value?.start)}
        onChange={(event) => {
          const nextDate = event.target.value
            ? new Date(event.target.value)
            : null;
          onChange?.(nextDate ? { start: nextDate, end: nextDate } : null);
        }}
      />
      {allowClear && value && (
        <button
          type="button"
          className="h-10 rounded-md border px-3 text-sm"
          onClick={(event) => {
            event.stopPropagation();
            onChange?.(null);
          }}
        >
          Clear
        </button>
      )}
    </div>
  );
}

